import React from 'react';

// import contact data
import { contact } from '../data';


const Contact = () => {
  return (
    <section className='section bg-primary' id='contact'>
      <div className='container mx-auto'>
        <div className='flex flex-col items-center text-center'>
          <h2 className='section-title before:content-contact relative before:absolute before:opacity-40 before:-top-7 before:-left-40 before:hidden before:lg:block'>
            Contact me
          </h2>
          <p className='subtitle'>
          Got a question, proposal or project or want to work together on something? Feel free to reach out.
          </p>
        </div>
        <div
          className='flex flex-col lg:gap-x-8 lg:flex-row'
        >
          <div
            className='flex flex-1 flex-col items-start space-y-8 mb-12 lg:mb-0 lg:pt-2'
          >
            {contact.map((item, index) => {
              const { icon, title, subtitle, description } = item;
              return (
                <div className='flex flex-col lg:flex-row gap-x-4' key={index}>
                  <div className='text-accent rounded-sm w-14 h-14 flex items-start justify-center mt-2 mb-4 lg:mb-0 text-2xl'>
                    {icon}
                  </div>
                  <div>
                    <h4 className='font-body text-xl mb-1'>{title}</h4>
                    <p className='mb-1 text-paragraph'>{subtitle}</p>
                    <p className='text-accent font-normal '>{description}</p>
                  </div>
                </div>
              );
            })}
          </div>
          <form method='POST' action ="https://getform.io/f/e3c770ce-b43e-43f2-9c51-67fe5b582677" className='space-y-8 w-full max-w-[780px]'
          >
            <div className='flex gap-8'>
              <input className='input' type='text' name='text' placeholder='Your name' />
              <input className='input' type='email' name='email' placeholder='Your email' />
            </div>
            <input className='input' type='text' name='subject' placeholder='Subject' />
            <textarea
              className='textarea'
              placeholder='Your message'
              name='message'
            ></textarea>
            <button className=" btn btn-lg border-accent border-2 text-accent hover:text-white hover:shadow-[inset_13rem_0_0_0] hover:shadow-accent duration-[400ms,700ms] transition-[color,box-shadow]">
              Send message
            </button>
          </form>
        </div>
      </div>
    </section>
  );
};

export default Contact;
